  url: 'https://router.home.elikesbikes.com/api/auth/login',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ username: $env.UNIFI_USER, password: $env.UNIFI_PASS }),
  returnFullResponse: true,
  skipSslCertificateValidation: true
});

const cookies = Array.isArray(loginResponse.headers['set-cookie'])
  ? loginResponse.headers['set-cookie'].join('; ')
  : loginResponse.headers['set-cookie'] || '';
const csrf = loginResponse.headers['x-csrf-token'] || '';

const logsResponse = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://router.home.elikesbikes.com/proxy/network/api/s/default/stat/alarm',
  headers: { 'Cookie': cookies, 'X-Csrf-Token': csrf },
  skipSslCertificateValidation: true
});

const logs = (logsResponse.data || []).map(e => ({
  time: new Date(e.datetime).toLocaleString(),
  type: e.key || 'Unknown',
  message: e.msg || 'No message',
  severity: e.archived ? 'resolved' : 'active',
  device: e.ap_displayName || e.gw_displayName || e.sw_displayName || 'Unknown'
}));

return JSON.stringify({ total: logs.length, logs: logs.slice(0, 50) });

const loginResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://router.home.elikesbikes.com/api/auth/login',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ username: $env.UNIFI_USER, password: $env.UNIFI_PASS }),
  returnFullResponse: true,
  skipSslCertificateValidation: true
});

const cookies = Array.isArray(loginResponse.headers['set-cookie'])
  ? loginResponse.headers['set-cookie'].join('; ')
  : loginResponse.headers['set-cookie'] || '';
const csrf = loginResponse.headers['x-csrf-token'] || '';

const apResponse = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://router.home.elikesbikes.com/proxy/network/api/s/default/stat/device',
  headers: { 'Cookie': cookies, 'X-Csrf-Token': csrf },
  skipSslCertificateValidation: true
});

const results = [];

for (const device of (apResponse.data || [])) {
  if (device.type !== 'uap') continue;

  const radios = device.radio_table_stats || [];
  for (const radio of radios) {
    const tx = radio.tx_packets || 0;
    const retries = radio.tx_retries || 0;
    const total = tx + retries;
    if (total === 0) continue;

    // Same formula UniFi UI uses: retries / (packets + retries)
    const retryPct = (retries / total) * 100;
    if (retryPct > 20) {
      results.push({
        ap_name: device.name || device.hostname || 'Unknown',
        mac: device.mac,
        radio: radio.name || 'Unknown',
        channel: radio.channel,
        tx_packets: tx,
        tx_retries: retries,
        retry_percent: retryPct.toFixed(1) + '%'
      });
    }
  }
}

results.sort((a, b) => parseFloat(b.retry_percent) - parseFloat(a.retry_percent));

return JSON.stringify({
  total_problematic_aps: results.length,
  threshold: '20%',
  access_points: results
});

const loginResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://router.home.elikesbikes.com/api/auth/login',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ username: $env.UNIFI_USER, password: $env.UNIFI_PASS }),
  returnFullResponse: true,
  skipSslCertificateValidation: true
});

const cookies = Array.isArray(loginResponse.headers['set-cookie'])
  ? loginResponse.headers['set-cookie'].join('; ')
  : loginResponse.headers['set-cookie'] || '';
const csrf = loginResponse.headers['x-csrf-token'] || '';

const apResponse = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://router.home.elikesbikes.com/proxy/network/api/s/default/stat/device',
  headers: { 'Cookie': cookies, 'X-Csrf-Token': csrf },
  skipSslCertificateValidation: true
});

// Build a map of channel -> list of APs on that channel
const channelMap = {};

for (const device of (apResponse.data || [])) {
  if (device.type !== 'uap') continue;

  for (const radio of (device.radio_table || [])) {
    const channel = radio.channel;
    const band = radio.radio === 'ng' ? '2.4GHz' : radio.radio === 'na' ? '5GHz' : '6GHz';
    const key = `${band}_ch${channel}`;

    if (!channelMap[key]) channelMap[key] = [];
    channelMap[key].push({
      ap_name: device.name || device.hostname || 'Unknown',
      mac: device.mac,
      band,
      channel,
      tx_power: radio.tx_power || 'auto'
    });
  }
}

// Only report channels where more than 1 AP is present
const conflicts = [];
for (const [key, aps] of Object.entries(channelMap)) {
  if (aps.length > 1) {
    conflicts.push({
      channel_key: key,
      band: aps[0].band,
      channel: aps[0].channel,
      ap_count: aps.length,
      access_points: aps
    });
  }
}

conflicts.sort((a, b) => b.ap_count - a.ap_count);

return JSON.stringify({
  total_conflicts: conflicts.length,
  note: 'Co-channel interference occurs when APs on the same channel can hear each other. For 2.4GHz use only channels 1, 6, 11. For 5GHz UniFi should auto-assign non-overlapping channels.',
  conflicts
});
